%%%%%%%%%% Function fLogReadV02.m %%%%%%%%%%% Function Log Reader, ver.1% Kei Nakamura% Created on Wednesday, March 22th 2006.% Modified on %% function [ttl,dat] = fLogRead1(fname)% returns the name of the columns (title) and a matrix% containing the whole data of the log file.% for trex system% ver.2: only for day=23function [ttl,dat] = fLogReadV03(fname)  %function headerfid = fopen(fname);     % file open('name','permission')   lin1 = fgetl(fid);      % read first line (title)numlin1 = double(lin1); % make char to number (tub = 9)tab = find(numlin1==9); % find subscripts = tub[delete,tabsiz] = size(tab);% size gives you a dimension, take bigger onettl = cell(tabsiz,2); % define a cell with tabsizettl{1,1} = 1;ttl{1,2} = lin1(1:tab(1)-1);for i=2:tabsiz    ttl{i,1} = i;    ttl{i,2}=lin1(tab(i-1)+1:tab(i)-1);endttl{i+1,1} = i+1;ttl{i+1,2} = lin1(tab(i)+1:end);%ttl{tabsiz+1,1} = tabsiz+1;%ttl{tabsiz+1,2} = lin1(tab(tabsiz)+1:end);num = fscanf(fid,'%e',[tabsiz+1,inf]);    % read formatted data file,                                        % inf: till the end%size(num)dat = num';fclose(fid);
